#!run
import {t} from "@hoge1e3/dom";
//import css from "@acepad/css";
import {did} from "@hoge1e3/dom-id";
import {c} from "@hoge1e3/component";
import {show} from "./acepad-widget.js";
import {fromVal} from "@hoge1e3/immer-path-ref";
import {ref,V,E,set,change} from "@hoge1e3/ref";
export async function main(...a){
  const [o,...args]=this.pickOptions(a);
  const id=did("w");
  //css container id
  const csscid=id.cssc;
  const style="width:100%;height:100%;overflow:scroll;";
  const userCont=t.div({id,style});
  const rdom=
    t.div(
      {id:csscid},
      css(o.css && this.resolve(o.css),csscid),
      userCont,
    );
  const w=show(rdom,{overlay:true,...o});
  Object.assign(w,{
    r:fromVal,
    t,c,id:id.c,V,E,set,change
  });
  let dom=args[0]||o.wmain;
  if(typeof dom==="function"){
    dom=await dom.call(this,w);
  }
  if(dom){
    userCont.appendChild(dom);
  }
  return w;
}
export function css(file,id){
  const cont=`#${id} {
  ${file?.exists() ? file.text() :""}
}`;
  const s=document.createElement("style");
  s.innerHTML=cont;
  //console.log(cont)
  return(s);
} 